#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim) {
    int i, j, k, offset, bx, by, tx, ty, idx;
    int array_offset, global_row_id, global_col_id, num_blocks;
    float sum;

    float *shadow = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    float *dia = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    float *peri_row = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    float *peri_col = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        // === lud_diagonal ===
        // Load diagonal block into shadow
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                array_offset += matrix_dim;
            }
        }

        // LU decomposition on shadow
        for (i = 0; i < BLOCK_SIZE - 1; i++) {
            // Update column (tx > i)
            for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
                for (j = 0; j < i; j++)
                    shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
            }

            // Update row
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                for (j = 0; j < i + 1; j++)
                    shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
        }

        // Write back lower part of diagonal
        array_offset = (offset + 1) * matrix_dim + offset;
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            for (i = 1; i < BLOCK_SIZE; i++) {
                m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
                array_offset += matrix_dim;
            }
        }

        num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

        // === lud_perimeter ===
        #pragma omp parallel for private(bx, tx, i, j, array_offset, idx) shared(m, dia, peri_row, peri_col, matrix_dim, offset, num_blocks)
        for (bx = 0; bx < num_blocks; bx++) {
            // Load data (first part - tx < BLOCK_SIZE)
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                idx = tx;
                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE / 2; i++) {
                    dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }

                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            }

            // Load data (second part - tx >= BLOCK_SIZE, mapped to idx = tx - BLOCK_SIZE)
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                idx = tx;
                array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
                for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                    dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }

                array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_col[idx * BLOCK_SIZE + i] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }
            }

            // Update peri_row
            for (idx = 0; idx < BLOCK_SIZE; idx++) {
                for (i = 1; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < i; j++)
                        peri_row[i * BLOCK_SIZE + idx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
                }
            }

            // Update peri_col
            for (idx = 0; idx < BLOCK_SIZE; idx++) {
                for (i = 0; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < i; j++)
                        peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                    peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
                }
            }

            // Write back peri_row
            for (idx = 0; idx < BLOCK_SIZE; idx++) {
                array_offset = (offset + 1) * matrix_dim + offset;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    m[array_offset + (bx + 1) * BLOCK_SIZE + idx] = peri_row[i * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            }

            // Write back peri_col
            for (idx = 0; idx < BLOCK_SIZE; idx++) {
                array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            }
        }

        // === lud_internal ===
        #pragma omp parallel for collapse(2) private(by, bx, tx, ty, i, sum, global_row_id, global_col_id) shared(m, peri_row, peri_col, matrix_dim, offset, num_blocks)
        for (by = 0; by < num_blocks; by++) {
            for (bx = 0; bx < num_blocks; bx++) {
                global_row_id = offset + (by + 1) * BLOCK_SIZE;
                global_col_id = offset + (bx + 1) * BLOCK_SIZE;

                // Load data
                for (ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (tx = 0; tx < BLOCK_SIZE; tx++) {
                        peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                        peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
                    }
                }

                // Update internal block
                for (ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (tx = 0; tx < BLOCK_SIZE; tx++) {
                        sum = 0;
                        for (i = 0; i < BLOCK_SIZE; i++)
                            sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
                        m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                    }
                }
            }
        }
    }

    // Final diagonal block
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
            array_offset += matrix_dim;
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++)
                shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++)
                shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
            array_offset += matrix_dim;
        }
    }

    free(shadow);
    free(dia);
    free(peri_row);
    free(peri_col);
}
